using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        private static void SeedData(SchoolContext context)
        {
            var department1 = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            var department2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 80000m,
                StartDate = new DateTime(2019, 9, 1)
            };

            context.Departments.AddRange(department1, department2);

            var course1 = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                Department = department1
            };
            var course2 = new Course
            {
                CourseID = 1002,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = 2,
                Department = department2
            };
            var course3 = new Course
            {
                CourseID = 1003,
                Title = "Physics",
                Credits = 3,
                DepartmentID = 1,
                Department = department1
            };

            context.Courses.AddRange(course1, course2, course3);

            var student1 = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            var student2 = new Student
            {
                ID = 2,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            var student3 = new Student
            {
                ID = 3,
                LastName = "Barzdukas",
                FirstMidName = "Arturas",
                EnrollmentDate = new DateTime(2024, 1, 15)
            };

            context.Students.AddRange(student1, student2, student3);

            var instructor1 = new Instructor
            {
                ID = 10,
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = new DateTime(2015, 3, 11)
            };
            var instructor2 = new Instructor
            {
                ID = 11,
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = new DateTime(2018, 7, 6)
            };

            context.Instructors.AddRange(instructor1, instructor2);

            context.Enrollments.AddRange(
                new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 1, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 1002, StudentID = 1, Grade = Grade.B },
                new Enrollment { EnrollmentID = 3, CourseID = 1001, StudentID = 2, Grade = Grade.C }
            );

            context.CourseAssignments.AddRange(
                new CourseAssignment { InstructorID = 10, CourseID = 1001 },
                new CourseAssignment { InstructorID = 11, CourseID = 1002 }
            );

            context.SaveChanges();
        }
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any notifications left from other tests (shared static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            _service.SendNotification("Department", "5", "Science", EntityOperation.DELETE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("DELETE", notification.Operation);
            Assert.Contains("deleted", notification.Message);
            Assert.Contains("Science", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUser_UsesSystem()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _service.ReceiveNotification();

            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
            Assert.Equal("C", third.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation but should not throw
            var exception = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_NullDisplayName_UsesEntityId()
        {
            _service.SendNotification("Student", "7", null, EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 7", notification.Message);
        }

        [Fact]
        public void SendNotification_EmptyDisplayName_UsesEntityId()
        {
            _service.SendNotification("Student", "7", "  ", EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 7", notification.Message);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 3, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(2, list);
            Assert.Contains(3, list);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 2);

            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 3 }, 5, 2, 2);

            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 5 }, 5, 3, 2);

            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2 }, 5, 1, 2);

            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(6, result[0]);
            Assert.Equal(10, result[4]);
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(new[] { 1, 2, 3 }, result.ToArray());
        }

        [Fact]
        public void Create_LastPage_ReturnRemainingItems()
        {
            var source = Enumerable.Range(1, 7).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 3);

            Assert.Single(result);
            Assert.Equal(7, result[0]);
        }

        [Fact]
        public void TotalPages_ExactDivision_CalculatesCorrectly()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void TotalPages_SingleItem_IsOne()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);

            Assert.Equal(1, list.TotalPages);
        }
    }
}

