using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        private static void SeedData(SchoolContext context)
        {
            var department1 = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            var department2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 80000m,
                StartDate = new DateTime(2019, 9, 1)
            };

            context.Departments.AddRange(department1, department2);

            var course1 = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                Department = department1
            };
            var course2 = new Course
            {
                CourseID = 1002,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = 2,
                Department = department2
            };
            var course3 = new Course
            {
                CourseID = 1003,
                Title = "Physics",
                Credits = 3,
                DepartmentID = 1,
                Department = department1
            };

            context.Courses.AddRange(course1, course2, course3);

            var student1 = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            var student2 = new Student
            {
                ID = 2,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };
            var student3 = new Student
            {
                ID = 3,
                LastName = "Barzdukas",
                FirstMidName = "Arturas",
                EnrollmentDate = new DateTime(2024, 1, 15)
            };

            context.Students.AddRange(student1, student2, student3);

            var instructor1 = new Instructor
            {
                ID = 10,
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = new DateTime(2015, 3, 11)
            };
            var instructor2 = new Instructor
            {
                ID = 11,
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = new DateTime(2018, 7, 6)
            };

            context.Instructors.AddRange(instructor1, instructor2);

            context.Enrollments.AddRange(
                new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 1, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 1002, StudentID = 1, Grade = Grade.B },
                new Enrollment { EnrollmentID = 3, CourseID = 1001, StudentID = 2, Grade = Grade.C }
            );

            context.CourseAssignments.AddRange(
                new CourseAssignment { InstructorID = 10, CourseID = 1001 },
                new CourseAssignment { InstructorID = 11, CourseID = 1002 }
            );

            context.SaveChanges();
        }
    }
}

