using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 3, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(2, list);
            Assert.Contains(3, list);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 2);

            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 3 }, 5, 2, 2);

            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 5 }, 5, 3, 2);

            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2 }, 5, 1, 2);

            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(6, result[0]);
            Assert.Equal(10, result[4]);
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(new[] { 1, 2, 3 }, result.ToArray());
        }

        [Fact]
        public void Create_LastPage_ReturnRemainingItems()
        {
            var source = Enumerable.Range(1, 7).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 3);

            Assert.Single(result);
            Assert.Equal(7, result[0]);
        }

        [Fact]
        public void TotalPages_ExactDivision_CalculatesCorrectly()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void TotalPages_SingleItem_IsOne()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);

            Assert.Equal(1, list.TotalPages);
        }
    }
}

