using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns("/tmp/wwwroot");
            _mockEnv.Setup(e => e.ContentRootPath).Returns("/tmp");
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_CoursesIncludeDepartment()
        {
            var result = _controller.Index() as ViewResult;
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);

            Assert.All(model, c => Assert.NotNull(c.Department));
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(course.Department);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
            Assert.IsType<Course>(result.Model);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_AddsToDatabase()
        {
            var course = new Course
            {
                CourseID = 2002,
                Title = "Another Course",
                Credits = 4,
                DepartmentID = 1
            };

            _controller.Create(course, null);

            Assert.Equal(4, _context.Courses.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 3001, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_WithInvalidImageExtension_ReturnsModelError()
        {
            var course = new Course
            {
                CourseID = 3001,
                Title = "Test",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.exe");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedImage_ReturnsModelError()
        {
            var course = new Course
            {
                CourseID = 3002,
                Title = "Test",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.Find(1001);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedCourse = new Course
            {
                CourseID = 1001,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Edit(updatedCourse, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1001, DepartmentID = 1 };

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_WithInvalidImageExtension_ReturnsModelError()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.pdf");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_WithOversizedImage_ReturnsModelError()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.png");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourse()
        {
            var result = _controller.DeleteConfirmed(1003);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(2, _context.Courses.Count());
        }

        #endregion
    }
}

